/* src/timer_mgr.c */
#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef struct {
    int timer_id;
    void (*callback)(void *data);
    void *user_data;
    int active;
    int expired;
} TimerContext;

TimerContext *timer_create_ctx(int id, void (*cb)(void*), void *data) {
    TimerContext *ctx = (TimerContext *)malloc(sizeof(TimerContext));  /* line 20 */
    if (!ctx) return NULL;  /* malloc return check - OK */

    ctx->timer_id = id;
    ctx->callback = cb;
    ctx->user_data = data;
    ctx->active = 1;    /* line 25: memleak FP - ctx IS returned on success */
    ctx->expired = 0;
    return ctx;
}

/* Called when timer expires - runs in interrupt/signal context */
void timer_expire_handler(TimerContext *ctx) {
    if (!ctx || !ctx->active) return;

    ctx->expired = 1;
    ctx->active = 0;

    /* Execute the callback */
    if (ctx->callback) {
        ctx->callback(ctx->user_data);
    }

    /* line 45: FREE the context after callback execution */
    free(ctx);
}

/* Called from main loop - may race with timer_expire_handler */
void timer_cleanup(TimerContext *ctx) {
    if (!ctx) return;

    /* BUG: If timer_expire_handler already freed ctx, this is USE-AFTER-FREE */
    if (ctx->expired) {  /* line 55: UAF - reading freed memory */
        printf("Timer %d already expired\n", ctx->timer_id);  /* UAF */
    }

    /* line 58: DOUBLE-FREE if timer_expire_handler already freed */
    free(ctx);
}

/* Example callback */
void on_timeout(void *data) {
    printf("Timeout for: %s\n", (const char *)data);
}

int main(void) {
    TimerContext *t = timer_create_ctx(1, on_timeout, "watchdog");
    if (!t) return 1;

    /* Simulate: timer expires in background */
    timer_expire_handler(t);  /* frees t */

    /* Main loop: tries to clean up - but t is already freed! */
    timer_cleanup(t);  /* UAF + double-free */

    return 0;
}
